mapper.select:
SELECT record_id, user_id, class_id, attendance_date, start_time, end_time, event_type_id, working_hours, break_time_minutes, overtime_hours, night_shift_hours, holiday_work_hours, remarks, created_at, updated_at, is_deleted
FROM attendance_records 
WHERE user_id = #{userId} 
AND attendance_date BETWEEN #{startDate} AND #{endDate}
AND is_deleted = false
ORDER BY attendance_date ASC
